mapper.select:
SELECT 전담자번호 memberNo, 지점 branch, 이름 memberName, 아이디 userId, 권한 role, 관리자권한 isAdmin, 등록일 regDate, 이메일 email, 전화번호 phoneNumber, 아이디사용여부 useStatus, 입사일 hireDate, 최종발령일 lastAssignDate, 근속기간구분 continuousPeriod, 조회순서 viewOrder, 실적작성여부 performanceWrite, 일일업무일지발급여부 dailyReportIssue, 배정가중치 assignWeight FROM J_참여자관리_로그인정보 WHERE 1=1
AND 지점 = #{searchBranch}
AND 이름 LIKE '%' + #{searchName} + '%'
AND 아이디 LIKE '%' + #{searchUserId} + '%'
AND 권한 = #{searchRole}
ORDER BY 조회순서 ASC, 전담자번호 ASC

mapper.insert:
INSERT INTO J_참여자관리_로그인정보 (
    전담자번호, 지점, 이름, 아이디, 비밀번호, 권한, 관리자권한,
    이메일, 전화번호, 아이디사용여부, 입사일, 최종발령일,
    조회순서, 실적작성여부, 일일업무일지발급여부, 배정가중치
) VALUES (
    #{memberNo}, #{branch}, #{memberName}, #{userId}, #{password}, #{role}, #{isAdmin},
    #{email}, #{phoneNumber}, #{useStatus}, #{hireDate}, #{lastAssignDate},
    #{viewOrder}, #{performanceWrite}, #{dailyReportIssue}, #{assignWeight}
)

mapper.update:
UPDATE J_참여자관리_로그인정보
SET 비밀번호 = #{password}
WHERE 전담자번호 = #{memberNo}

UPDATE J_참여자관리_로그인정보
SET 아이디사용여부 = #{useStatus}
WHERE 전담자번호 = #{memberNo}

mapper.select:
SELECT COUNT(*) FROM J_참여자관리_로그인정보
WHERE 아이디 = #{userId}

    AND 전담자번호 != #{memberNo}
